mapper.select:
SELECT * FROM ( SELECT B.*, DENSE_RANK() OVER ( ORDER BY B.DONG_NM, B.HO, B.HO_NO ) AS HOUSE_RN FROM METER_BASE B WHERE 1 = 1
AND ( B.DISPLAY_DONG_HO LIKE '%' || #{searchVO.keyword} || '%' OR B.DONG_NM LIKE '%' || #{searchVO.keyword} || '%' OR B.HO LIKE '%' || #{searchVO.keyword} || '%' )
) WHERE HOUSE_RN BETWEEN #{startRow} AND #{endRow} ORDER BY HOUSE_RN, CASE BILL_ITEM_CD WHEN 'ELC' THEN 1 WHEN 'WTR' THEN 2 WHEN 'GAS' THEN 3 ELSE 4 END
